Replaced the CSS-based trail with a high-performance Canvas implementation. This creates a smooth, glowing gradient "ribbon" trail that fades out elegantly behind the cursor.

```tsx
import React, { useEffect, useRef, useState } from 'react';

const CustomCursor: React.FC = () => {
  const cursorRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isHovering, setIsHovering] = useState(false);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    let animationId: number;

    // Mouse state
    let mouseX = window.innerWidth / 2;
    let mouseY = window.innerHeight / 2;

    // Trail history
    // We store a history of points to draw the line
    const trail: {x: number, y: number}[] = [];
    const TRAIL_LENGTH = 25;

    const resize = () => {
      if (canvas) {
        canvas.width = window.innerWidth;
        canvas.height = window.innerHeight;
      }
    };
    window.addEventListener('resize', resize);
    resize();

    const handleMouseMove = (e: MouseEvent) => {
      mouseX = e.clientX;
      mouseY = e.clientY;

      // 1. Instant update for main dot (Precision)
      if (cursorRef.current) {
        cursorRef.current.style.transform = `translate3d(${mouseX}px, ${mouseY}px, 0) translate(-50%, -50%)`;
      }

      // Check hover state for scaling effect
      const target = e.target as HTMLElement;
      const isClickable = 
        target.tagName === 'A' || 
        target.tagName === 'BUTTON' || 
        target.closest('a') || 
        target.closest('button') ||
        target.classList.contains('cursor-pointer');

      setIsHovering(!!isClickable);
    };

    const render = () => {
      if (!canvas || !ctx) return;

      // Clear canvas for fresh frame
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // Add new point to trail history
      trail.push({ x: mouseX, y: mouseY });

      // Maintain fixed trail length
      if (trail.length > TRAIL_LENGTH) {
        trail.shift();
      }

      // Draw the glowing trail
      if (trail.length > 1) {
        const head = trail[trail.length - 1];
        const tail = trail[0];

        // Create a gradient along the path (Transparent -> Brand Color)
        // This makes the tail look like it's fading away
        const gradient = ctx.createLinearGradient(tail.x, tail.y, head.x, head.y);
        gradient.addColorStop(0, 'rgba(34, 211, 238, 0)');   // Fade out at tail
        gradient.addColorStop(1, 'rgba(34, 211, 238, 0.8)'); // Bright at head

        ctx.beginPath();

        // Start at the tail
        ctx.moveTo(trail[0].x, trail[0].y);

        // Draw smooth curves between points using quadratic interpolation
        for (let i = 1; i < trail.length - 1; i++) {
          const xc = (trail[i].x + trail[i+1].x) / 2;
          const yc = (trail[i].y + trail[i+1].y) / 2;
          ctx.quadraticCurveTo(trail[i].x, trail[i].y, xc, yc);
        }

        // Connect to the head (current mouse pos)
        ctx.lineTo(trail[trail.length-1].x, trail[trail.length-1].y);

        // Style the line
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.lineWidth = isHovering ? 5 : 3; // Thicker when hovering
        ctx.strokeStyle = gradient;

        // Add Neon Glow
        ctx.shadowBlur = 15;
        ctx.shadowColor = '#22d3ee';

        ctx.stroke();
      }

      animationId = requestAnimationFrame(render);
    };

    window.addEventListener('mousemove', handleMouseMove);
    animationId = requestAnimationFrame(render);

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationId);
    };
  }, [isHovering]);

  return (
    <>
      {/* Canvas layer for the glowing trail */}
      <canvas 
        ref={canvasRef}
        className="pointer-events-none fixed inset-0 z-[9998]"
      />

      {/* Main precision dot (always stays on top) */}
      <div 
        ref={cursorRef}
        className={`pointer-events-none fixed top-0 left-0 z-[9999] bg-white rounded-full mix-blend-difference transition-[width,height] duration-200 ease-out ${
          isHovering ? 'w-4 h-4' : 'w-2 h-2'
        }`}
        style={{ 
          transform: 'translate(-50%, -50%)',
          boxShadow: '0 0 10px rgba(255,255,255,0.5)' 
        }}
      />
    </>
  );
};

export default CustomCursor;

