## components/AiChat.tsx

Перевел интерфейс чата, системные инструкции для бота (чтобы он отвечал на русском) и сообщения об ошибках.

```tsx
import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, GenerateContentResponse, Chat } from "@google/genai";
import { Send, Bot, User, AlertTriangle, Loader2, Globe } from 'lucide-react';

interface Message {
  role: 'user' | 'model';
  text: string;
  isError?: boolean;
}

const AiChat: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: 'Личность: Shou. Спрашивай о психологии рынка, стратегии или риск-менеджменте.' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [retryStatus, setRetryStatus] = useState<string>('');

  const chatContainerRef = useRef<HTMLDivElement>(null);
  const chatRef = useRef<Chat | null>(null);

  const apiKey = process.env.API_KEY;

  // Debugging
  useEffect(() => {
    if (!apiKey) {
      console.warn("⚠️ AI Chat: API Key is MISSING.");
    } else {
      console.log("✅ AI Chat: API Key present.");
    }
  }, [apiKey]);

  const scrollToBottom = () => {
    if (chatContainerRef.current) {
      const { scrollHeight, clientHeight } = chatContainerRef.current;
      chatContainerRef.current.scrollTo({
        top: scrollHeight - clientHeight,
        behavior: 'smooth'
      });
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, retryStatus]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    if (!apiKey) {
      setMessages(prev => [...prev, { 
        role: 'user', text: input 
      }, {
        role: 'model',
        text: 'КРИТИЧЕСКАЯ ОШИБКА: API ключ отсутствует. Проверьте настройки Vercel.',
        isError: true
      }]);
      setInput('');
      return;
    }

    const userMessage = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    setIsLoading(true);
    setRetryStatus('');

    const maxRetries = 3;
    let attempt = 0;
    let success = false;

    while (attempt < maxRetries && !success) {
      try {
        // Initialize chat if needed
        if (!chatRef.current) {
          const ai = new GoogleGenAI({ apiKey: apiKey });
          chatRef.current = ai.chats.create({
            model: 'gemini-2.5-flash',
            config: {
              systemInstruction: "Ты ИИ-ассистент профессионального трейдера-минималиста по имени 'Shou'. " +
                "Твой тон спокоен, дисциплинирован и краток. Отвечай на русском языке. " +
                "Ты специализируешься на концепциях Smart Money (SMC), Price Action и психологии трейдинга. " +
                "Держи ответы в пределах 50 слов, если не попросят рассказать подробнее.",
            },
          });
        }

        const resultStream = await chatRef.current.sendMessageStream({ message: userMessage });

        // If successful, clear any retry status and prepare for stream
        setRetryStatus('');
        setMessages(prev => [...prev, { role: 'model', text: '' }]);

        let fullResponse = "";
        for await (const chunk of resultStream) {
          const c = chunk as GenerateContentResponse;
          const text = c.text || "";
          fullResponse += text;

          setMessages(prev => {
            const newArr = [...prev];
            newArr[newArr.length - 1].text = fullResponse;
            return newArr;
          });
        }

        success = true;

      } catch (error: any) {
        console.error(`Attempt ${attempt + 1} failed:`, error);

        const rawErrorMessage = error instanceof Error ? error.message : JSON.stringify(error);

        // Check for specific errors
        const isOverloaded = rawErrorMessage.includes('503') || error.status === 503;

        // Check for Geo-Block (400 User location not supported)
        const isGeoBlocked = rawErrorMessage.includes('location') || rawErrorMessage.includes('400');

        if (isGeoBlocked) {
            setMessages(prev => [...prev, { 
                role: 'model', 
                text: "ГЕО-БЛОКИРОВКА: Google API недоступен в вашем регионе (РФ). Пожалуйста, включите VPN (США/Европа) для работы ИИ.", 
                isError: true 
            }]);
            break; // Don't retry, it won't work without VPN
        }

        if (isOverloaded && attempt < maxRetries - 1) {
          attempt++;
          const delay = attempt * 2000; // 2s, 4s...
          setRetryStatus(`Сервер занят. Повторная попытка... (${attempt}/${maxRetries})`);
          await new Promise(resolve => setTimeout(resolve, delay));
        } else {
          // Fatal error or ran out of retries

          let userFriendlyError = `Google API Error: ${rawErrorMessage}`;
          if (isOverloaded) {
             userFriendlyError = "Перегрузка системы: Серверы ИИ сейчас заняты. Попробуйте позже.";
          } else if (rawErrorMessage.includes('404')) {
             userFriendlyError = "Системная ошибка: Версия модели не найдена. (404)";
          } else if (rawErrorMessage.includes('400')) {
             userFriendlyError = "Ошибка запроса (400): Проверьте подключение или VPN.";
          }

          setMessages(prev => [...prev, { 
            role: 'model', 
            text: userFriendlyError, 
            isError: true 
          }]);
          break; // Exit loop
        }
      }
    }

    setIsLoading(false);
    setRetryStatus('');
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="w-full max-w-3xl mx-auto h-[60vh] md:h-[500px] flex flex-col bg-black/40 backdrop-blur-md rounded-2xl border border-white/10 overflow-hidden shadow-[0_0_40px_rgba(34,211,238,0.05)]">

      <div 
        ref={chatContainerRef}
        className="flex-1 overflow-y-auto p-6 space-y-6 scroll-smooth custom-scrollbar mt-2"
      >
        {messages.map((msg, idx) => (
          <div 
            key={idx} 
            className={`flex gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}
          >
            <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center ${
              msg.role === 'user' 
                ? 'bg-neutral-800 text-neutral-400' 
                : msg.isError ? 'bg-red-500/20 text-red-500' : 'bg-brand/20 text-brand'
            }`}>
              {msg.role === 'user' ? <User size={14} /> : msg.isError ? <Globe size={14}/> : <Bot size={14} />}
            </div>

            <div className={`max-w-[80%] p-4 rounded-2xl text-sm leading-relaxed break-words ${
              msg.role === 'user'
                ? 'bg-neutral-900 text-neutral-200 rounded-tr-sm'
                : msg.isError
                  ? 'bg-red-500/10 text-red-400 border border-red-500/20 rounded-tl-sm font-mono text-xs'
                  : 'bg-brand/5 text-brand/90 border border-brand/10 rounded-tl-sm shadow-[0_0_15px_rgba(34,211,238,0.05)]'
            }`}>
              {msg.text}
            </div>
          </div>
        ))}

        {/* Loading / Retry Status Indicator */}
        {(isLoading || retryStatus) && (
            <div className="flex gap-4">
                 <div className="flex-shrink-0 w-8 h-8 rounded-full bg-brand/20 text-brand flex items-center justify-center">
                    <Bot size={14} />
                </div>
                <div className="bg-brand/5 border border-brand/10 p-4 rounded-2xl rounded-tl-sm flex items-center gap-3">
                    {retryStatus ? (
                      <>
                        <Loader2 size={16} className="animate-spin text-yellow-500" />
                        <span className="text-xs text-yellow-500 font-mono">{retryStatus}</span>
                      </>
                    ) : (
                      <>
                        <div className="w-1.5 h-1.5 bg-brand/50 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}/>
                        <div className="w-1.5 h-1.5 bg-brand/50 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}/>
                        <div className="w-1.5 h-1.5 bg-brand/50 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}/>
                      </>
                    )}
                </div>
            </div>
        )}
      </div>

      <div className="p-4 bg-black/20 border-t border-white/5">
        <div className="relative flex items-center gap-2">
            <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder="Спроси о Smart Money концепциях..."
                className="w-full bg-neutral-900/50 text-white text-sm rounded-xl pl-4 pr-12 py-4 focus:outline-none focus:ring-1 focus:ring-brand/50 transition-all placeholder:text-neutral-600"
                disabled={isLoading}
            />
            <button 
                onClick={handleSend}
                disabled={!input.trim() || isLoading}
                className="absolute right-2 p-2 bg-brand text-black rounded-lg hover:bg-white transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            >
                <Send size={16} />
            </button>
        </div>
      </div>
    </div>
  );
};

export default AiChat;
