                        <h3 className="text-xl font-bold font-mono text-white">
                           {item.title}
                        </h3>
                     </div>
                     {/* Render description if available */}
                     {item.description && (
                       <p className="text-sm text-dark-muted mt-1 pl-4">{item.description}</p>
                     )}
                  </div>

                  {/* Render content based on type */}
                  {item.type === 'widget' ? (
                    <div className="w-full h-[500px] md:h-[600px] rounded-xl overflow-hidden border border-white/10 shadow-lg">
                      <TradingViewWidget symbol={item.symbol!} containerId={item.id} />
                    </div>
                  ) : (
                    <a 
                      href={item.link || item.url} 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="w-full rounded-xl overflow-hidden border border-white/10 shadow-2xl group relative block cursor-pointer bg-black"
                    >
                      {/* Static Image with referrerPolicy to bypass hotlink protection */}
                      <img 
                        src={item.url} 
                        alt={item.title} 
                        referrerPolicy="no-referrer"
                        className="w-full h-auto object-cover hover:scale-[1.01] transition-transform duration-500"
                      />
                      <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex items-center justify-center">
                         <div className="flex items-center gap-2 text-white bg-black/80 px-4 py-2 rounded-full border border-white/20 backdrop-blur-sm">
                            <ExternalLink size={16} />
                            <span className="text-sm font-medium">Открыть в TradingView</span>
                         </div>
                      </div>
                    </a>
                  )}
                </div>
              ))}
            </div>
          </div>
        </div>
