import { ChevronDown, CandlestickChart, Sparkles, LayoutDashboard, ExternalLink, ArrowLeft, Radar } from 'lucide-react';
import { RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, Radar as RechartsRadar, ResponsiveContainer, Tooltip } from 'recharts';

interface FadeInProps {
  isActive: boolean;
  delay?: number;
  className?: string;
  children: React.ReactNode;
}

// Reusable FadeIn Component for smooth transitions
const FadeIn: React.FC<FadeInProps> = ({ 
  isActive, 
  delay = 0, 
  className = "", 
  children 
}) => (
  <div 
    className={`transition-all duration-1000 ease-out transform ${
      isActive 
        ? 'opacity-100 translate-y-0 blur-0' 
        : 'opacity-0 translate-y-12 blur-sm'
    } ${className}`}
    style={{ transitionDelay: `${delay}ms` }}
  >
    {children}
  </div>
);

const App: React.FC = () => {
  // 'main' = Scrolling Page, 'dashboard' = Separate View
  const [viewMode, setViewMode] = useState<'main' | 'dashboard'>('main');

  // Initialize as empty string so the first section starts "hidden" and animates in
  const [activeSection, setActiveSection] = useState<string>('');
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  // Reset scroll to top on mount and trigger initial animation
  useEffect(() => {
    if (viewMode === 'main') {
      if (scrollContainerRef.current) {
        scrollContainerRef.current.scrollTo(0, 0);
      }
      window.scrollTo(0, 0);

      const timer = setTimeout(() => {
        setActiveSection(SECTIONS[0].id);
      }, 100);
      return () => clearTimeout(timer);
    }
  }, [viewMode]);

  // Handle Intersection Observer to update active section on scroll (Only when in main view)
  useEffect(() => {
    if (viewMode !== 'main') return;

    const container = scrollContainerRef.current;
    if (!container) return;

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            setActiveSection(entry.target.id);
          }
        });
      },
      {
        root: container,
        threshold: 0.3, 
      }
    );

    SECTIONS.forEach((section) => {
      const element = document.getElementById(section.id);
      if (element) observer.observe(element);
    });

    return () => {
      if (container) {
        observer.disconnect();
      }
    };
  }, [viewMode]);

