## api/chat.js

**Серверный прокси Vercel.** Этот файл позволит ИИ работать в России. (Он должен лежать в папке `api`, которую Vercel автоматически распознает как серверные функции).

```javascript
export const config = {
  runtime: 'edge',
};

export default async function handler(req) {
  // Handle CORS for local dev if needed, though mostly for Vercel
  if (req.method === 'OPTIONS') {
    return new Response(null, {
      headers: {
        'Access-Control-Allow-Origin': '*',
        'Access-Control-Allow-Methods': 'POST, OPTIONS',
        'Access-Control-Allow-Headers': 'Content-Type',
      },
    });
  }

  if (req.method !== 'POST') {
    return new Response('Method Not Allowed', { status: 405 });
  }

  try {
    const { messages } = await req.json();
    // Use the last message as prompt
    const prompt = messages[messages.length - 1].text;

    const apiKey = process.env.VITE_API_KEY || process.env.API_KEY;

    if (!apiKey) {
       return new Response(JSON.stringify({ error: 'Server API Key missing' }), { status: 500 });
    }

    // Direct fetch to Google API (Bypasses client-side Geo-block because Vercel servers are in US)
    const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${apiKey}`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        contents: [{ parts: [{ text: prompt }] }]
      })
    });

    const data = await response.json();

    // Check for Google errors
    if (data.error) {
        return new Response(JSON.stringify(data), { status: 400 });
    }

    // Return data to frontend
    return new Response(JSON.stringify(data), {
      headers: { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' },
    });

  } catch (error) {
    return new Response(JSON.stringify({ error: error.message }), { status: 500 });
  }
}
