  const [viewMode, setViewMode] = useState<'main' | 'dashboard'>('main');

  // Initialize as empty string so the first section starts "hidden" and animates in
  const [activeSection, setActiveSection] = useState<string>('');
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  // Reset scroll to top on mount and trigger initial animation
  useEffect(() => {
    if (viewMode === 'main') {
      if (scrollContainerRef.current) {
        scrollContainerRef.current.scrollTo(0, 0);
      }
      window.scrollTo(0, 0);

      const timer = setTimeout(() => {
        setActiveSection(SECTIONS[0].id);
      }, 100);
      return () => clearTimeout(timer);
    }
  }, [viewMode]);

  // Handle Intersection Observer to update active section on scroll (Only when in main view)
  useEffect(() => {
    if (viewMode !== 'main') return;

    const container = scrollContainerRef.current;
    if (!container) return;

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            setActiveSection(entry.target.id);
          }
        });
      },
      {
        root: container,
        threshold: 0.3, 
      }
    );

    SECTIONS.forEach((section) => {
      const element = document.getElementById(section.id);
      if (element) observer.observe(element);
    });

    return () => {
      if (container) {
        observer.disconnect();
      }
    };
  }, [viewMode]);

  const handleNavigation = (id: string) => {
    if (viewMode === 'dashboard') {
      // If we are in dashboard, switch back to main, allow render, then scroll
      setViewMode('main');
      setTimeout(() => {
        const element = document.getElementById(id);
        if (element && scrollContainerRef.current) {
          element.scrollIntoView({ behavior: 'auto' }); // Auto scroll instantly after switch
          setActiveSection(id);
        }
      }, 10);
    } else {
