      >
        {messages.map((msg, idx) => (
          <div 
            key={idx} 
            className={`flex gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}
          >
            <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center ${
              msg.role === 'user' 
                ? 'bg-neutral-800 text-neutral-400' 
                : msg.isError ? 'bg-red-500/20 text-red-500' : 'bg-brand/20 text-brand'
            }`}>
              {msg.role === 'user' ? <User size={14} /> : msg.isError ? <AlertTriangle size={14}/> : <Bot size={14} />}
            </div>

            <div className={`max-w-[80%] p-4 rounded-2xl text-sm leading-relaxed break-words ${
              msg.role === 'user'
                ? 'bg-neutral-900 text-neutral-200 rounded-tr-sm'
                : msg.isError
