import React, { useEffect, useRef } from 'react';

// Types for our chart simulation
interface Candle {
  x: number;
  open: number;
  close: number;
  high: number;
  low: number;
  opacity: number;
}

interface Layer {
  speed: number;
  yOffset: number;
  scaleY: number;
  color: string;
  type: 'line' | 'candle';
  data: number[];
  candles: Candle[];
  lastPrice: number;
  offsetX: number; 
  step: number;
}

// Shooting Star Interface
interface ShootingStar {
  id: number;
  x: number;
  y: number;
  length: number;
  speed: number;
  size: number;
  opacity: number;
}

const AnimatedBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let width = window.innerWidth;
    let height = window.innerHeight;

    const resize = () => {
      width = window.innerWidth;
      height = window.innerHeight;
      canvas.width = width;
      canvas.height = height;
    };
    window.addEventListener('resize', resize);
    resize();

    // --- Shooting Stars State ---
    let shootingStars: ShootingStar[] = [];
    let nextSpawnTime = 0; // Frame counter for spawning

    const spawnShootingStars = () => {
      const count = Math.floor(Math.random() * 2) + 1; // Spawn 1 or 2 stars at once
      for (let i = 0; i < count; i++) {
        // Start mainly from top or right side
        const startX = Math.random() * width * 0.5 + width * 0.5; // Right half
        const startY = Math.random() * height * 0.5 - height * 0.2; // Top area

        shootingStars.push({
          id: Math.random(),
          x: startX,
          y: startY,
          length: Math.random() * 80 + 150, // Long tails
          speed: Math.random() * 10 + 15,   // Fast speed
          size: Math.random() * 1.5 + 1,
          opacity: 1
        });
      }
    };

    // --- Initialize Chart Layers ---
    const layers: Layer[] = [
      // Background Line Chart
      {
        speed: 0.15, 
        yOffset: height * 0.5,
        scaleY: height * 0.85, 
        color: 'rgba(34, 211, 238, 0.03)',
        type: 'line',
        step: 60, 
        offsetX: 0,
        data: [],
        candles: [],
        lastPrice: 0.5
      },
      // Mid Line Chart
      {
        speed: 0.3, 
        yOffset: height * 0.6,
        scaleY: height * 0.65,
        color: 'rgba(168, 85, 247, 0.04)', 
        type: 'line',
        step: 40,
        offsetX: 0,
        data: [],
        candles: [],
        lastPrice: 0.5
      },
      // Foreground Candlesticks
      {
        speed: 0.6, 
        yOffset: height * 0.5, 
        scaleY: 600, 
        color: '#22d3ee',
        type: 'candle',
        step: 0,
        offsetX: 0,
        data: [],
        candles: [],
        lastPrice: 0.5
      }
    ];

    // Initialize Data for Line Charts
    layers.forEach(layer => {
      if (layer.type === 'line') {
        const pointsNeeded = Math.ceil(width / layer.step) + 4;
        for(let i=0; i<pointsNeeded; i++) {
           layer.lastPrice += (Math.random() - 0.5) * 0.15;
           if(layer.lastPrice > 0.9) layer.lastPrice -= 0.1;
           if(layer.lastPrice < 0.1) layer.lastPrice += 0.1;
           layer.data.push(layer.lastPrice);
        }
      }
    });

    // Seed initial candles
    const candleWidth = 12;
    const gap = 8;
    const totalCandles = Math.ceil(width / (candleWidth + gap)) + 5;

    let currentPrice = 0.5;
    for (let i = 0; i < totalCandles; i++) {
      const change = (Math.random() - 0.5) * 0.15; 
      const open = currentPrice;
      const close = currentPrice + change;
      const high = Math.max(open, close) + Math.random() * 0.08;
      const low = Math.min(open, close) - Math.random() * 0.08;

      if (close > 0.9) currentPrice -= 0.1;
      else if (close < 0.1) currentPrice += 0.1;
      else currentPrice = close;

      layers[2].candles.push({
        x: i * (candleWidth + gap),
        open,
        close,
        high,
        low,
        opacity: Math.random() * 0.5 + 0.2
      });
    }
    layers[2].lastPrice = currentPrice;

    // Animation Loop
    const render = () => {
      ctx.clearRect(0, 0, width, height);

      // --- Manage Shooting Stars ---
      nextSpawnTime--;
      if (nextSpawnTime <= 0) {
        // Reduced frequency: 0.5% chance per frame (was 2%, so 4x reduction, requested 50% but this feels better for "not too frequent")
        if (Math.random() < 0.01) { 
          spawnShootingStars();
          nextSpawnTime = Math.random() * 200 + 150; // Longer wait between bursts
        }
      }

      // Draw and update stars
      for (let i = shootingStars.length - 1; i >= 0; i--) {
        const star = shootingStars[i];

        // Move Top-Right to Bottom-Left
        star.x -= star.speed;
        star.y += star.speed * 0.6;

        // Draw trail (gradient line)
        const tailX = star.x + star.length;
        const tailY = star.y - star.length * 0.6;

        const gradient = ctx.createLinearGradient(star.x, star.y, tailX, tailY);
        gradient.addColorStop(0, 'rgba(255, 255, 255, 1)');
        gradient.addColorStop(1, 'rgba(255, 255, 255, 0)');

        ctx.beginPath();
        ctx.moveTo(star.x, star.y);
        ctx.lineTo(tailX, tailY);
        ctx.strokeStyle = gradient;
        ctx.lineWidth = star.size;
        ctx.lineCap = 'round';
        ctx.stroke();

        // --- Enhanced Glow Effect ---
        // 1. Core bright glow
        ctx.beginPath();
        ctx.arc(star.x, star.y, star.size * 2, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(255, 255, 255, 0.9)';
        ctx.shadowBlur = 20;
        ctx.shadowColor = 'rgba(255, 255, 255, 0.9)';
        ctx.fill();

        // 2. Outer atmospheric glow (Cyan tinted)
        ctx.beginPath();
        ctx.arc(star.x, star.y, star.size * 6, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(34, 211, 238, 0.15)'; // faint cyan
        ctx.shadowBlur = 40;
        ctx.shadowColor = 'rgba(34, 211, 238, 0.4)';
        ctx.fill();

        ctx.shadowBlur = 0;

        // Remove if off screen
        if (star.x < -star.length || star.y > height + star.length) {
          shootingStars.splice(i, 1);
        }
      }

      // --- Draw Background Grid ---
      ctx.strokeStyle = 'rgba(255, 255, 255, 0.015)';
      ctx.lineWidth = 1;
      const gridSize = 120;
      const time = Date.now() * 0.005; 
      const xOffset = time % gridSize;

      for (let x = -xOffset; x < width; x += gridSize) {
        ctx.beginPath();
        ctx.moveTo(x, 0);
        ctx.lineTo(x, height);
        ctx.stroke();
      }
      for (let y = 0; y < height; y += gridSize) {
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(width, y);
        ctx.stroke();
      }

      // --- Process & Draw Chart Layers ---
      layers.forEach((layer) => {
        if (layer.type === 'line') {
          layer.offsetX -= layer.speed;
          if (layer.offsetX <= -layer.step) {
            layer.offsetX += layer.step;
            layer.data.shift();
            layer.lastPrice += (Math.random() - 0.5) * 0.12;
            const centerDist = 0.5 - layer.lastPrice;
            layer.lastPrice += centerDist * 0.02; 
            layer.data.push(layer.lastPrice);
          }

          ctx.beginPath();
          ctx.strokeStyle = layer.color;
          ctx.lineWidth = 2;

          for (let i = 0; i < layer.data.length; i++) {
            const x = (i * layer.step) + layer.offsetX;
            const y = layer.yOffset + (layer.data[i] - 0.5) * layer.scaleY;
            if (i === 0) ctx.moveTo(x, y);
            else {
              const prevX = ((i - 1) * layer.step) + layer.offsetX;
              const prevY = layer.yOffset + (layer.data[i - 1] - 0.5) * layer.scaleY;
              const cx = (prevX + x) / 2;
              const cy = (prevY + y) / 2;
              ctx.quadraticCurveTo(prevX, prevY, cx, cy);
              if (i === layer.data.length - 1) ctx.lineTo(x, y);
            }
          }
          ctx.stroke();
          ctx.lineTo(width, height);
          ctx.lineTo(0, height);
          ctx.fillStyle = layer.color.replace(/[\d.]+\)$/, '0.005)');
          ctx.fill();

        } else if (layer.type === 'candle') {
          layer.candles.forEach(c => { c.x -= layer.speed; });
          if (layer.candles.length > 0 && layer.candles[0].x < -50) layer.candles.shift();

          const lastCandle = layer.candles[layer.candles.length - 1];
          if (lastCandle && lastCandle.x < width + 50) {
            const startX = lastCandle.x + candleWidth + gap;
            const momentum = (Math.random() - 0.5) * 0.05;
            const change = (Math.random() - 0.5) * 0.25 + momentum;
            const open = layer.lastPrice;
            let close = open + change;
            if (close > 1.2) close -= 0.1;
            if (close < -0.2) close += 0.1;
            const high = Math.max(open, close) + Math.random() * 0.15;
            const low = Math.min(open, close) - Math.random() * 0.15;

            layer.candles.push({
              x: startX,
              open,
              close,
              high,
              low,
              opacity: 1
            });
            layer.lastPrice = close;
          }

          layer.candles.forEach(c => {
            const isBull = c.close >= c.open;
            const candleHeight = Math.abs(c.close - c.open) * layer.scaleY;
            const yOpen = layer.yOffset - (c.open - 0.5) * layer.scaleY;
            const yClose = layer.yOffset - (c.close - 0.5) * layer.scaleY;
            const yHigh = layer.yOffset - (c.high - 0.5) * layer.scaleY;
            const yLow = layer.yOffset - (c.low - 0.5) * layer.scaleY;
            const yTopBody = Math.min(yOpen, yClose);

            if (isBull) {
              ctx.fillStyle = '#22d3ee';
              ctx.strokeStyle = '#22d3ee';
            } else {
              ctx.fillStyle = '#404040'; 
              ctx.strokeStyle = '#525252';
            }

            if (c === lastCandle) {
               ctx.shadowBlur = 20;
               ctx.shadowColor = isBull ? '#22d3ee' : '#ef4444';
               if (!isBull) { ctx.fillStyle = '#ef4444'; ctx.strokeStyle = '#ef4444'; }
            } else {
               ctx.shadowBlur = 0;
            }

            ctx.beginPath();
            ctx.moveTo(c.x + candleWidth / 2, yHigh);
            ctx.lineTo(c.x + candleWidth / 2, yLow);
            ctx.lineWidth = 1;
            ctx.stroke();

            const bodyH = Math.max(candleHeight, 1);
            ctx.fillRect(c.x, yTopBody, candleWidth, bodyH);
          });
          ctx.shadowBlur = 0;
        }
      });

      const gradient = ctx.createRadialGradient(width/2, height/2, height/3, width/2, height/2, height);
      gradient.addColorStop(0, 'rgba(10, 10, 10, 0.3)'); 
      gradient.addColorStop(0.8, 'rgba(10, 10, 10, 0.7)');
      gradient.addColorStop(1, 'rgba(10, 10, 10, 0.98)');
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, width, height);

      animationFrameId = requestAnimationFrame(render);
    };

    render();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return <canvas ref={canvasRef} className="fixed inset-0 z-0 w-full h-full pointer-events-none blur-[3px] opacity-60" />;
};

