      layers[2].candles.push({
        x: i * (candleWidth + gap),
        open,
        close,
        high,
        low,
        opacity: Math.random() * 0.5 + 0.2
      });
    }
    layers[2].lastPrice = currentPrice;

    // Animation Loop
    const render = () => {
      ctx.clearRect(0, 0, width, height);

      // --- Manage Shooting Stars ---
      nextSpawnTime--;
      if (nextSpawnTime <= 0) {
        // Even less frequent: 0.5% chance per frame to trigger the timer
        if (Math.random() < 0.005) { 
          spawnShootingStars();
          // Much longer pause between stars (600 to 1000 frames ~ 10 to 16 seconds)
          // This reduces frequency significantly
          nextSpawnTime = Math.random() * 400 + 600; 
        }
      }

      // Draw and update stars
      for (let i = shootingStars.length - 1; i >= 0; i--) {
        const star = shootingStars[i];

        // Move Top-Right to Bottom-Left at high speed
        star.x -= star.speed;
        star.y += star.speed * 0.7; 

        // Draw trail (gradient line)
        const tailX = star.x + star.length;
        const tailY = star.y - star.length * 0.7;

        const gradient = ctx.createLinearGradient(star.x, star.y, tailX, tailY);
        gradient.addColorStop(0, 'rgba(255, 255, 255, 0.8)');
        gradient.addColorStop(1, 'rgba(255, 255, 255, 0)');

        ctx.beginPath();
        ctx.moveTo(star.x, star.y);
        ctx.lineTo(tailX, tailY);
        ctx.strokeStyle = gradient;
        ctx.lineWidth = star.size; // Thicker trail
        ctx.lineCap = 'round';
        ctx.stroke();

        // --- Enhanced Star Glow (The Head) ---
        // 1. Intense Core (White hot)
        ctx.beginPath();
        ctx.arc(star.x, star.y, star.size, 0, Math.PI * 2);
        ctx.fillStyle = '#ffffff';
        ctx.shadowBlur = 30; // Increased blur
        ctx.shadowColor = '#ffffff';
        ctx.fill();

        // 2. Radiant Halo (Very Bright Cyan/Blue tint)
        ctx.beginPath();
        ctx.arc(star.x, star.y, star.size * 5, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(200, 240, 255, 0.4)'; // Brighter halo
        ctx.shadowBlur = 60; // Large atmospheric glow
        ctx.shadowColor = 'rgba(34, 211, 238, 0.8)'; // Strong Cyan
        ctx.fill();

        ctx.shadowBlur = 0; // Reset

        // Remove if off screen
        if (star.x < -star.length || star.y > height + star.length) {
          shootingStars.splice(i, 1);
        }
      }

      // --- Draw Background Grid ---
      ctx.strokeStyle = 'rgba(255, 255, 255, 0.015)';
      ctx.lineWidth = 1;
      const gridSize = 120;
      const time = Date.now() * 0.005; 
      const xOffset = time % gridSize;

      for (let x = -xOffset; x < width; x += gridSize) {
        ctx.beginPath();
        ctx.moveTo(x, 0);
        ctx.lineTo(x, height);
        ctx.stroke();
      }
      for (let y = 0; y < height; y += gridSize) {
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(width, y);
        ctx.stroke();
      }

      // --- Process & Draw Chart Layers ---
      layers.forEach((layer) => {
        if (layer.type === 'line') {
          layer.offsetX -= layer.speed;
          if (layer.offsetX <= -layer.step) {
            layer.offsetX += layer.step;
            layer.data.shift();
            layer.lastPrice += (Math.random() - 0.5) * 0.12;
            const centerDist = 0.5 - layer.lastPrice;
            layer.lastPrice += centerDist * 0.02; 
            layer.data.push(layer.lastPrice);
          }

          ctx.beginPath();
          ctx.strokeStyle = layer.color;
          ctx.lineWidth = 2;

          for (let i = 0; i < layer.data.length; i++) {
            const x = (i * layer.step) + layer.offsetX;
            const y = layer.yOffset + (layer.data[i] - 0.5) * layer.scaleY;
            if (i === 0) ctx.moveTo(x, y);
            else {
              const prevX = ((i - 1) * layer.step) + layer.offsetX;
              const prevY = layer.yOffset + (layer.data[i - 1] - 0.5) * layer.scaleY;
              const cx = (prevX + x) / 2;
              const cy = (prevY + y) / 2;
              ctx.quadraticCurveTo(prevX, prevY, cx, cy);
              if (i === layer.data.length - 1) ctx.lineTo(x, y);
            }
          }
          ctx.stroke();
          ctx.lineTo(width, height);
          ctx.lineTo(0, height);
          ctx.fillStyle = layer.color.replace(/[\d.]+\)$/, '0.005)');
          ctx.fill();

        } else if (layer.type === 'candle') {
          layer.candles.forEach(c => { c.x -= layer.speed; });
          if (layer.candles.length > 0 && layer.candles[0].x < -50) layer.candles.shift();

          const lastCandle = layer.candles[layer.candles.length - 1];
          if (lastCandle && lastCandle.x < width + 50) {
            const startX = lastCandle.x + candleWidth + gap;
            const momentum = (Math.random() - 0.5) * 0.05;
            const change = (Math.random() - 0.5) * 0.25 + momentum;
            const open = layer.lastPrice;
            let close = open + change;
            if (close > 1.2) close -= 0.1;
            if (close < -0.2) close += 0.1;
            const high = Math.max(open, close) + Math.random() * 0.15;
            const low = Math.min(open, close) - Math.random() * 0.15;

            layer.candles.push({
              x: startX,
              open,
              close,
              high,
              low,
              opacity: 1
            });
            layer.lastPrice = close;
          }

          layer.candles.forEach(c => {
            const isBull = c.close >= c.open;
            const candleHeight = Math.abs(c.close - c.open) * layer.scaleY;
            const yOpen = layer.yOffset - (c.open - 0.5) * layer.scaleY;
            const yClose = layer.yOffset - (c.close - 0.5) * layer.scaleY;
            const yHigh = layer.yOffset - (c.high - 0.5) * layer.scaleY;
            const yLow = layer.yOffset - (c.low - 0.5) * layer.scaleY;
            const yTopBody = Math.min(yOpen, yClose);

            if (isBull) {
              ctx.fillStyle = '#22d3ee';
              ctx.strokeStyle = '#22d3ee';
            } else {
              ctx.fillStyle = '#404040'; 
              ctx.strokeStyle = '#525252';
            }

            if (c === lastCandle) {
               ctx.shadowBlur = 20;
               ctx.shadowColor = isBull ? '#22d3ee' : '#ef4444';
               if (!isBull) { ctx.fillStyle = '#ef4444'; ctx.strokeStyle = '#ef4444'; }
            } else {
               ctx.shadowBlur = 0;
            }

            ctx.beginPath();
            ctx.moveTo(c.x + candleWidth / 2, yHigh);
            ctx.lineTo(c.x + candleWidth / 2, yLow);
            ctx.lineWidth = 1;
            ctx.stroke();

            const bodyH = Math.max(candleHeight, 1);
            ctx.fillRect(c.x, yTopBody, candleWidth, bodyH);
          });
          ctx.shadowBlur = 0;
        }
      });

      const gradient = ctx.createRadialGradient(width/2, height/2, height/3, width/2, height/2, height);
      gradient.addColorStop(0, 'rgba(10, 10, 10, 0.3)'); 
      gradient.addColorStop(0.8, 'rgba(10, 10, 10, 0.7)');
      gradient.addColorStop(1, 'rgba(10, 10, 10, 0.98)');
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, width, height);

      animationFrameId = requestAnimationFrame(render);
    };

    render();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return <canvas ref={canvasRef} className="fixed inset-0 z-0 w-full h-full pointer-events-none blur-[3px] opacity-60" />;
};

export default AnimatedBackground;

Это отличная идея. Перенос проекта в VS Code даст тебе полный контроль над кодом.

Вот пошаговая инструкция, как развернуть этот проект на твоем компьютере с нуля.

### Шаг 1: Подготовка программ
Тебе понадобятся две программы (если их нет, скачай и установи):
1.  **VS Code** (Редактор кода).
2.  **Node.js** (Движок, чтобы запускать сайт). Скачивай версию **LTS**.

### Шаг 2: Создание основы проекта
1.  Создай пустую папку на рабочем столе, назови её `shou-trade`.
2.  Открой эту папку через **VS Code** (`File` -> `Open Folder`).
3.  В VS Code открой терминал (`Terminal` -> `New Terminal`) и введи команду:
    ```bash
    npm create vite@latest . -- --template react-ts
    ```
    *(Если спросит подтверждение, нажми `y` и Enter).*

### Шаг 3: Установка библиотек
В том же терминале введи эти команды по очереди (это установит все инструменты, которые мы использовали: графики, иконки, ИИ, Tailwind):

```bash
npm install
npm install lucide-react recharts @google/genai
npm install -D tailwindcss postcss autoprefixer
npx tailwindcss init -p
```

### Шаг 4: Распределение файлов
Сейчас у тебя в папке `src` лежат стандартные файлы. Нам нужно заменить их на твой код.

**1. Настройка Tailwind CSS**
Открой файл `tailwind.config.js` (он в корне) и замени всё внутри на этот код:
```javascript
/** @type {import('tailwindcss').Config} */
export default {
  content: [
    "./index.html",
    "./src/**/*.{js,ts,jsx,tsx}",
  ],
  theme: {
    extend: {
      colors: {
        brand: {
          DEFAULT: '#22d3ee',
          glow: 'rgba(34, 211, 238, 0.6)',
        },
        dark: {
          bg: '#0a0a0a',
          card: '#171717',
          text: '#e5e5e5',
          muted: '#737373'
        }
      },
      fontFamily: {
        sans: ['Inter', 'sans-serif'],
        mono: ['Fira Code', 'monospace'],
      },
      dropShadow: {
        'glow': '0 0 20px rgba(34, 211, 238, 0.5)',
        'glow-sm': '0 0 10px rgba(34, 211, 238, 0.4)',
      },
      animation: {
        'fade-in-up': 'fadeInUp 0.8s ease-out forwards',
        'pulse-slow': 'pulse 4s cubic-bezier(0.4, 0, 0.6, 1) infinite',
        'scroll-left': 'scrollLeft 20s linear infinite',
      },
      keyframes: {
        fadeInUp: {
          '0%': { opacity: '0', transform: 'translateY(20px)' },
          '100%': { opacity: '1', transform: 'translateY(0)' },
        },
        scrollLeft: {
          '0%': { transform: 'translateX(0)' },
          '100%': { transform: 'translateX(-50%)' },
        }
      }
    },
  },
  plugins: [],
}
```

**2. Добавление стилей**
Открой файл `src/index.css` и замени всё на:
```css
@import url('https://fonts.googleapis.com/css2?family=Fira+Code:wght@300;400;500&family=Inter:wght@300;400;600;900&display=swap');

@tailwind base;
@tailwind components;
@tailwind utilities;

